import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./styles/InviteAdmin.css";

const InviteAdmin = ({ auth, setAuth }) => {
  const [email, setEmail] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setError("");
    setSuccess("");

    try {
      const response = await fetch("https://localhost:7235/api/auth/invite-admin", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${localStorage.getItem("accessToken")}`
        },
        body: JSON.stringify({ email }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Failed to send invitation");
      }

      setSuccess("Invitation sent successfully!");
      setEmail("");
    } catch (error) {
      setError(error.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="admin-container">
      <header className="admin-header">
        <div className="header-content">
          <h1><i className="fas fa-user-plus"></i> Invite Admin</h1>
          <button 
            className="btn back-btn"
            onClick={() => navigate("/admin/messages")}
          >
            <i className="fas fa-arrow-left"></i> Dashboard
          </button>
        </div>
      </header>

      <main className="admin-content">
        <div className="admin-card">
          {error && <div className="alert error"><i className="fas fa-exclamation-circle"></i> {error}</div>}
          {success && <div className="alert success"><i className="fas fa-check-circle"></i> {success}</div>}

          <form onSubmit={handleSubmit} className="admin-form">
            <div className="form-group">
              <label htmlFor="email"><i className="fas fa-envelope"></i> Email Address</label>
              <input
                type="email"
                id="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                placeholder="Enter admin email"
                className="modern-input"
              />
            </div>
            <button 
              type="submit" 
              className="btn primary-btn"
              disabled={isLoading}
            >
              {isLoading ? (
                <><i className="fas fa-spinner fa-spin"></i> Sending...</>
              ) : (
                <><i className="fas fa-paper-plane"></i> Send Invitation</>
              )}
            </button>
          </form>
        </div>
      </main>
    </div>
  );
};

export default InviteAdmin;
